//quantileScale.js
import { colorscale_helpers } from './colorscale-helpers';
import { defined } from '../utils/zcutils';

colorscale_helpers.quantileScale = function() {
    var domain = [],
        range = [],
        quantiles = [];

    function scale(x) {
        var index;
        quantiles.forEach(function(d, i) {
            if (x >= d[0] && x <= d[1]) {
                index = i;
            }
        });
        return defined(index) ? range[index] : null;
    }

    scale.domain = function(_) {
        if (arguments.length) {
            domain = _;
            quantiles = [];
            for (var i = 0; i < domain.length; i += 2) {
                quantiles.push([domain[i], domain[i + 1]]);
            }
            return scale;
        }
        return domain;
    };

    scale.range = function(_) {
        if (arguments.length) {
            range = _;
            return scale;
        }
        return range;
    };

    scale.copy = function() {
        return colorscale_helpers
            .quantileScale()
            .domain(domain)
            .range(range);
    };
    return scale;
};

export var _quantileScale = colorscale_helpers.quantileScale;
